INSERT INTO workflow_templates (id, template_id, name, steps, created_at, updated_at) VALUES
  (1, 'workflow-v1', '默认工作流', '[{"id":"solution-design","name":"头脑风暴设计","instructionPrompt":"使用头脑风暴Skill思考。先完成 Spec-Driven 方案设计。必须基于任务上下文输出可直接执行的设计结果，并将设计文档写入 docs：1）明确目标、范围与验收标准；2）梳理用户场景、边界条件与异常场景；3）说明关键约束、依赖与风险；4）给出实现思路、模块改动点与任务拆分；5）定义测试策略、关键测试用例与完成标准；6）列出需要前置确认的问题。最后输出可供下游步骤直接消费的 summary。","agentId":1},{"id":"feature-development","name":"开发实现","instructionPrompt":"基于上游设计文档与 summary，按 TDD 完成开发实现。要求：1）先对齐验收标准与测试用例；2）优先补齐或新增失败测试，再完成实现并让相关测试通过；3）严格按设计范围修改，避免无关改动；4）优先复用现有能力与实现模式；5）必要时同步更新文档、配置或脚本；6）总结核心改动点、影响范围、测试执行结果与遗留问题。最后输出可供测试阶段直接消费的 summary。","agentId":2},{"id":"qa-validation","name":"测试验证","instructionPrompt":"基于上游设计文档、开发 summary、代码改动与测试结果执行测试验证。至少覆盖：1）验收标准是否全部满足；2）新增或修改测试是否覆盖核心路径、边界场景与异常场景；3）相关回归是否受影响；4）发现的问题、复现方式与影响判断；5）当前结果是否允许进入评审。最后输出可供评审阶段直接消费的 summary。","agentId":4},{"id":"final-review","name":"结果评审","instructionPrompt":"基于前序设计文档、各步骤 summary、代码 diff 与测试结果完成最终评审。重点确认：1）实现是否满足规格、范围与验收标准；2）设计、实现与测试是否保持一致；3）测试策略与测试结果是否足以支撑交付；4）是否存在明显质量、安全或可维护性风险；5）是否还有阻塞交付的问题；6）给出明确评审结论与后续处理建议。","agentId":1}]', '2026-03-27T00:00:00.000Z', '2026-03-31T01:05:56.698Z');
INSERT INTO workflow_templates (id, template_id, name, steps, created_at, updated_at) VALUES
  (2, 'dev-feature-sdd-tdd-v1', '研发交付：标准功能开发', '[{"id":"feature-sdd-requirement-clarification","name":"SDD 需求澄清与验收定义","instructionPrompt":"你当前负责标准功能开发交付的 SDD 需求澄清与验收定义阶段。目标：把原始需求整理成可执行的交付说明，明确范围、非目标、验收标准和关键场景。执行要求：1）提炼业务目标、用户价值和成功标准；2）明确范围内内容、范围外内容、依赖前提和待确认问题；3）梳理核心路径、边界场景和异常路径；4）输出下游设计与测试可直接使用的验收定义。禁止事项：1）不要直接进入方案或实现；2）不要忽略边界与非目标；3）不要输出模糊结论。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单（必须列出已产出文档、测试、实现或验证结果）、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1},{"id":"feature-sdd-solution-design","name":"SDD 方案设计与任务拆解","instructionPrompt":"你当前负责标准功能开发交付的 SDD 方案设计与任务拆解阶段。目标：基于已澄清需求输出可实施方案，并拆出相对独立的阶段边界。执行要求：1）明确模块改动点、接口或数据影响、关键实现路径；2）说明实施顺序、阶段边界、依赖关系和回滚思路；3）输出测试策略与真实前端验证关注点；4）确保下游实现和验证只依赖当前 summary 也能继续执行。禁止事项：1）不要直接写实现代码；2）不要遗漏测试与回滚考虑；3）不要把多个职责混成一个阶段。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1},{"id":"feature-tdd-test-design","name":"TDD 测试先行设计","instructionPrompt":"你当前负责标准功能开发交付的 TDD 测试先行设计阶段。目标：先定义失败测试、验证范围和通过标准，再进入实现。执行要求：1）列出要先失败的单元测试、集成测试或关键验证点；2）说明核心路径、边界场景、异常场景和回归范围；3）单独列出真实前端验证清单、验证环境和关键交互路径；4）明确哪些内容尚未覆盖。禁止事项：1）不要先写实现再补测试；2）不要把自动化测试通过等同于验收通过；3）不要遗漏真实前端验证要求。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"feature-tdd-minimal-implementation","name":"TDD 最小实现","instructionPrompt":"你当前负责标准功能开发交付的 TDD 最小实现阶段。目标：基于前序失败测试与方案设计完成最小必要实现。执行要求：1）先对齐验收标准和失败测试，再完成聚焦实现；2）优先复用现有模式，控制改动范围；3）说明通过了哪些验证、还缺哪些验证；4）记录影响范围和遗留问题。禁止事项：1）不要扩展需求；2）不要做无关重构；3）不要省略验证依据。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":2},{"id":"feature-automation-validation","name":"自动化测试与回归验证","instructionPrompt":"你当前负责标准功能开发交付的自动化测试与回归验证阶段。目标：独立确认自动化测试层面的质量结论。执行要求：1）执行核心路径、边界场景、异常场景和必要回归验证；2）区分已验证、未验证、验证失败和环境问题；3）说明测试结果、影响范围和残余风险；4）为真实前端验收提供明确输入。禁止事项：1）不要直接信任开发结论；2）不要把未验证项当作通过；3）不要把自动化测试通过直接视为完整交付通过。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"feature-real-frontend-validation","name":"真实前端验收","instructionPrompt":"你当前负责标准功能开发交付的真实前端验收阶段。目标：在真实页面和真实交互上下文中确认功能可用且满足验收标准。执行要求：1）说明验证环境、页面入口和操作路径；2）验证核心路径、边界交互和异常交互；3）记录页面表现、交互反馈、发现的问题和未覆盖范围；4）明确当前结果是否达到进入交付评审的条件。禁止事项：1）不要仅凭单元测试、集成测试或 mock 结果给通过结论；2）不要忽略 UI/交互问题；3）不要模糊说明验证范围。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"feature-delivery-review","name":"交付评审","instructionPrompt":"你当前负责标准功能开发交付的交付评审阶段。目标：综合需求、设计、实现、自动化验证和真实前端验收结果，判断是否具备交付条件。执行要求：1）检查各阶段结论是否一致、交付物是否齐全；2）区分阻塞问题、重要风险和一般建议；3）明确是否建议继续推进、合入或上线；4）总结后续跟进事项。禁止事项：1）不要只复述上游 summary；2）不要遗漏交付结论；3）不要把风险藏在模糊表述里。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1}]', '2026-03-30T00:00:00.000Z', '2026-03-31T01:05:18.860Z');
INSERT INTO workflow_templates (id, template_id, name, steps, created_at, updated_at) VALUES
  (3, 'frontend-delivery-sdd-tdd-v1', '研发交付：前端页面/交互', '[{"id":"frontend-sdd-scenario-definition","name":"SDD 交互需求与验收场景定义","instructionPrompt":"你当前负责前端页面/交互交付的 SDD 交互需求与验收场景定义阶段。目标：明确用户任务流、页面状态矩阵和验收场景。执行要求：1）梳理主流程、边界流程、异常流程；2）明确页面状态、交互节点、提示反馈和失败场景；3）定义验收标准、非目标和依赖；4）为后续方案设计与验证提供完整场景输入。禁止事项：1）不要直接进入页面实现；2）不要忽略空状态、错误态和权限态；3）不要只写抽象需求。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1},{"id":"frontend-sdd-ui-design","name":"SDD 前端方案设计","instructionPrompt":"你当前负责前端页面/交互交付的 SDD 前端方案设计阶段。目标：输出页面结构、组件边界、状态流转和接口依赖方案。执行要求：1）明确组件职责、数据流、状态更新和异常处理策略；2）说明接口依赖、兼容性风险和实施顺序；3）列出需要重点关注的交互一致性与可用性问题；4）保证后续实现与验证能按阶段独立交接。禁止事项：1）不要直接写实现代码；2）不要遗漏状态切换和错误反馈；3）不要把交互设计和实现细节混在一起。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1},{"id":"frontend-tdd-test-design","name":"TDD 测试设计与前端验证脚本","instructionPrompt":"你当前负责前端页面/交互交付的 TDD 测试设计与前端验证脚本阶段。目标：先定义失败测试和真实页面走查脚本，再进入实现。执行要求：1）列出需要先失败的组件、页面或集成测试；2）明确关键 DOM 断言、状态切换断言和交互反馈断言；3）输出真实前端手工验证脚本，包含页面入口、操作步骤和预期结果；4）说明未覆盖项和风险。禁止事项：1）不要先写页面实现；2）不要只列自动化测试而忽略真实交互验证；3）不要把验证脚本写成模糊说明。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"frontend-tdd-implementation","name":"TDD 页面实现","instructionPrompt":"你当前负责前端页面/交互交付的 TDD 页面实现阶段。目标：基于失败测试和页面方案完成最小必要实现。执行要求：1）围绕已定义测试补齐页面、组件和交互实现；2）控制范围，优先保证核心路径与关键状态可用；3）记录受影响组件、样式或接口依赖；4）说明当前通过了哪些验证、还有哪些验证待完成。禁止事项：1）不要扩展需求；2）不要混入无关重构；3）不要省略实现依据。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":2},{"id":"frontend-automation-validation","name":"自动化测试执行","instructionPrompt":"你当前负责前端页面/交互交付的自动化测试执行阶段。目标：执行组件、页面或集成测试并输出可信结果。执行要求：1）执行核心路径、边界场景、异常场景和必要回归测试；2）区分测试失败、环境问题和未执行项；3）总结覆盖情况、残余风险和是否建议进入真实前端验收；4）补充仍未自动化覆盖的关键交互。禁止事项：1）不要把未执行项当作通过；2）不要忽略环境问题；3）不要把自动化测试结果直接等同于页面可用性结论。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"frontend-real-ui-validation","name":"真实前端走查验收","instructionPrompt":"你当前负责前端页面/交互交付的真实前端走查验收阶段。目标：在真实页面中确认交互、样式和可用性满足预期。执行要求：1）说明验证环境、页面入口、操作步骤和实际结果；2）检查交互一致性、状态反馈、样式表现和异常提示；3）记录 UI/UX 问题、兼容性问题和未覆盖范围；4）明确当前结果是否满足交付要求。禁止事项：1）不要仅凭自动化测试通过给出通过结论；2）不要忽略视觉和交互问题；3）不要省略真实操作路径。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"frontend-release-review","name":"发布评审","instructionPrompt":"你当前负责前端页面/交互交付的发布评审阶段。目标：综合场景定义、方案设计、实现、自动化测试和真实前端验收结果，判断是否具备发布或交付条件。执行要求：1）检查交付物是否齐全，验收标准是否闭环；2）区分阻塞问题、重要风险和一般建议；3）明确是否建议合入、发布或继续迭代；4）总结后续关注事项。禁止事项：1）不要只汇总前序结果；2）不要隐藏交互风险；3）不要缺少最终结论。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1}]', '2026-03-30T00:00:00.000Z', '2026-03-31T01:05:09.270Z');
INSERT INTO workflow_templates (id, template_id, name, steps, created_at, updated_at) VALUES
  (4, 'bugfix-sdd-tdd-v1', '研发交付：缺陷修复与防回归', '[{"id":"bugfix-sdd-problem-definition","name":"SDD 问题澄清与复现定义","instructionPrompt":"你当前负责缺陷修复与防回归交付的 SDD 问题澄清与复现定义阶段。目标：明确问题现象、稳定复现路径、影响范围和修复验收标准。执行要求：1）整理前置条件、复现步骤、预期行为与实际行为；2）识别受影响模块、用户影响和关键回归路径；3）明确修复边界、非目标和待确认问题；4）为根因分析和失败测试设计提供可靠输入。禁止事项：1）不要跳过复现条件；2）不要直接进入修复实现；3）不要模糊描述影响范围。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1},{"id":"bugfix-sdd-root-cause-design","name":"SDD 根因与修复设计","instructionPrompt":"你当前负责缺陷修复与防回归交付的 SDD 根因与修复设计阶段。目标：基于证据确认根因并输出最小修复方案。执行要求：1）给出根因假设与证据链；2）说明受影响代码、数据或配置路径；3）定义最小修复范围、回滚思路和验证策略；4）为失败测试补齐和最小实现提供清晰输入。禁止事项：1）不要在证据不足时武断定性；2）不要直接进入实现；3）不要遗漏回归风险。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1},{"id":"bugfix-tdd-regression-test-design","name":"TDD 失败测试补齐","instructionPrompt":"你当前负责缺陷修复与防回归交付的 TDD 失败测试补齐阶段。目标：先用失败测试锁定问题，再进入修复实现。执行要求：1）定义能够稳定暴露原问题的失败测试或缺失验证；2）说明关键回归路径、边界场景和异常场景；3）列出真实前端复现与验收时必须覆盖的操作链路；4）总结当前尚未覆盖的风险。禁止事项：1）不要先修复再补测试；2）不要把无法稳定复现的问题直接判定为已修复；3）不要遗漏真实前端复现要求。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"bugfix-tdd-minimal-fix","name":"TDD 最小修复实现","instructionPrompt":"你当前负责缺陷修复与防回归交付的 TDD 最小修复实现阶段。目标：在最小必要改动范围内修复问题并控制副作用。执行要求：1）围绕失败测试与根因分析完成最小修复；2）说明修复点、影响范围和潜在副作用；3）确认相关验证是否已通过、哪些验证仍待执行；4）避免无关重构。禁止事项：1）不要扩大修复范围；2）不要跳过防回归考虑；3）不要只说「已修复」而没有验证依据。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":2},{"id":"bugfix-automation-regression-validation","name":"自动化回归验证","instructionPrompt":"你当前负责缺陷修复与防回归交付的自动化回归验证阶段。目标：确认原问题被自动化验证锁住且未引入明显回归。执行要求：1）执行原问题验证、关键回归路径和必要边界场景；2）区分验证通过、验证失败、环境问题和未执行项；3）说明残余风险和是否建议进入真实前端复现验收；4）为后续真实前端验收提供清晰输入。禁止事项：1）不要直接相信开发结论；2）不要把未验证项当作通过；3）不要把自动化回归通过直接等同于问题已彻底关闭。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"bugfix-real-frontend-validation","name":"真实前端复现与验收","instructionPrompt":"你当前负责缺陷修复与防回归交付的真实前端复现与验收阶段。目标：在真实界面中确认原问题无法复现，并检查相邻交互链路。执行要求：1）说明验证环境、页面入口、原始复现路径和新的验证结果；2）确认原问题在真实界面中已不可复现；3）检查相邻功能、边界交互和异常交互是否受影响；4）记录发现的问题、限制和未覆盖范围。禁止事项：1）不要仅凭自动化测试结果给出通过结论；2）不要忽略相邻交互链路；3）不要模糊说明复现和验证过程。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":4},{"id":"bugfix-delivery-review","name":"修复交付评审","instructionPrompt":"你当前负责缺陷修复与防回归交付的修复交付评审阶段。目标：综合问题澄清、根因设计、失败测试、修复实现、自动化验证和真实前端验收结果，判断当前缺陷是否具备关闭或继续推进条件。执行要求：1）检查修复证据链是否完整、交付物是否齐全；2）区分阻塞问题、重要风险和一般建议；3）明确是否建议关闭问题、合入修复或继续观察；4）总结后续观察项。禁止事项：1）不要只复述前序 summary；2）不要隐藏剩余风险；3）不要缺少最终结论。输出要求：最终只输出 summary，并严格包含以下小节：本步结论（通过/有风险通过/不通过/需补充信息）、已完成内容、交付物清单、未完成或范围外内容、风险与影响、阻塞与待确认问题、给下游步骤的交接建议。","agentId":1}]', '2026-03-30T00:00:00.000Z', '2026-03-31T01:05:14.558Z');
INSERT INTO workflow_templates (id, template_id, name, steps, created_at, updated_at) VALUES
  (5, 'frontend-dev-v1', '前端开发：通用功能交付', '[{"id":"frontend-requirement-and-prototype","name":"需求分析与原型绘制","instructionPrompt":"理解原始需求，产出可预览的页面原型。交付物：1）需求分析写入 docs/workflow/01-requirement-analysis.md，含交互流程、页面状态矩阵、边界场景和非目标；2）用项目现有 UI 框架搭建页面原型到源码目录，模拟数据填充，覆盖正常态、空状态、加载态、错误态。不实现真实业务逻辑，不引入新依赖。summary 只引用文件路径，不重复内容。","agentId":3,"requiresConfirmation":true},{"id":"frontend-solution-design","name":"方案设计","instructionPrompt":"基于上游原型和需求分析，输出可执行的前端技术方案。交付物写入 docs/workflow/02-solution-design.md，含组件结构、状态管理、接口依赖、实施顺序、回退策略和验收标准。不写实现代码，不遗漏空状态和错误态。summary 只引用文件路径。","agentId":1},{"id":"frontend-test-design","name":"测试先行设计","requiresConfirmation":true,"instructionPrompt":"基于原型和方案，先定义失败测试和页面走查清单。交付物：1）测试用例写入 docs/workflow/03-test-cases.md，含编号、名称、类型、步骤、预期结果和优先级；2）自动化测试代码写在项目测试目录。覆盖核心路径、边界和异常场景。summary 只引用文件路径。","agentId":4},{"id":"frontend-implementation","name":"前端功能实现","instructionPrompt":"基于方案和测试清单，将原型转化为完整功能实现。交付物：1）实现说明写入 docs/workflow/04-implementation-notes.md，含修改文件清单、新增组件、接口变更和关键决策；2）功能代码写在源码目录。替换模拟数据为真实接口，实现完整业务逻辑和异常处理，不扩展需求，不混入无关重构。summary 只引用文件路径。","agentId":3},{"id":"frontend-test-execution","name":"测试执行与结果记录","instructionPrompt":"按测试清单逐条执行，记录每条用例结果。交付物写入 docs/workflow/05-test-report.md，含逐条结果表（编号、名称、预期、实际、通过/失败）、失败原因分析、未执行项说明、汇总统计（通过/失败/未执行数）。不跳过用例，不把未执行标为通过。summary 只引用文件路径和汇总数字。","agentId":4},{"id":"frontend-delivery-review","name":"交付评审","instructionPrompt":"综合各阶段交付物和测试结果，判断是否具备交付条件。交付物写入 docs/workflow/06-delivery-review.md，含交付物完整性检查、验收达成情况、测试关键发现、阻塞问题与风险、最终结论。不只复述上游 summary，不隐藏失败风险，给出明确结论。summary 只引用文件路径和评审结论。","agentId":1,"requiresConfirmation":true}]', '2026-04-01T00:00:00.000Z', '2026-04-01T00:00:00.000Z');
INSERT INTO workflow_runs (id, task_id, workflow_template_id, workflow_template_snapshot, mastra_run_id, status, current_step, steps, worktree_path, branch, context, created_at, updated_at) VALUES
